@namespace sv_b3aee266d46a422aa507df110c2c832b.Components.Pages.Application

<nav class="step-indicator" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isClickable = isCompleted && !isCurrent;

            <li class="step-item @(isCurrent ? "current" : isCompleted ? "completed" : "future")"
                @onclick="() => { if (isClickable) OnStepClicked.InvokeAsync(step); }"
                role="button"
                tabindex="@(isClickable ? 0 : -1)"
                aria-current="@(isCurrent ? "step" : null)">
                <span class="step-number">
                    @if (isCompleted && !isCurrent)
                    {
                        <span class="checkmark">&#10003;</span>
                    }
                    else
                    {
                        @(step + 1)
                    }
                </span>
                <span class="step-label">@StepNames[step]</span>
            </li>

