@using sv_b3aee266d46a422aa507df110c2c832b.Models
@namespace sv_b3aee266d46a422aa507df110c2c832b.Components.Pages.Application

<div class="step-content">
    <h2>Personal Information</h2>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-error">@ErrorMessage</div>
    }

    <div class="form-group">
        <label>Full Name <span class="required">*</span></label>
        <input type="text" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
    </div>

    <div class="form-group">
        <label>Email <span class="required">*</span></label>
        <input type="email" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
        @if (IsValidatingEmail)
        {
            <span class="validation-hint">Validating email...</span>
        }
    </div>

    <div class="form-group">
        <label>Phone <span class="required">*</span></label>
        <input type="tel" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
    </div>

    <div class="form-group">
        <label>Address <span class="required">*</span></label>
        <textarea rows="2" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State ZIP"></textarea>
    </div>

    <div class="step-buttons">
        <span></span>
        <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidatingEmail">
            @(IsValidatingEmail ? "Validating..." : "Next →")
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? ErrorMessage;
    private bool IsValidatingEmail;

    private async Task HandleNext()
    {
