+@namespace sv_b3aee266d46a422aa507df110c2c832b.Components.Pages.Application
+
+<div class="step-content">
+    <h2>References</h2>
+
+    @if (!string.IsNullOrEmpty(ErrorMessage))
+    {
+        <div class="alert alert-error">@ErrorMessage</div>
+    }
+
+    @for (int i = 0; i < References.Count; i++)
+    {
+        var index = i;
+        <ReferenceForm Reference="References[index]"
+                       Index="index"
+                       ShowRemove="References.Count > 2"
+                       OnRemove="() => RemoveReference(index)" />
+    }
+
+    @if (References.Count < 3)
+    {
+        <button type="button" class="btn btn-secondary" @onclick="AddReference">
+            + Add Reference
+        </button>
+    }
+
+    <div class="step-buttons">
+        <button type="button" class="btn btn-outline" @onclick="OnBack">← Back</button>
+        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
+    </div>
+</div>
