@namespace sv_b3aee266d46a422aa507df110c2c832b.Components.Pages.Application

<div class="step-content">
    <h2>Cover Letter</h2>

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea rows="12"
                  @bind="CoverLetterText"
                  @bind:event="oninput"
                  maxlength="@MaxLength"
                  placeholder="Tell us why you're a great fit for this role..."></textarea>
        <div class="char-count @(CoverLetterText.Length > MaxLength ? "over-limit" : "")">
            @CoverLetterText.Length / @MaxLength characters
        </div>
    </div>

    <div class="step-buttons">
        <button type="button" class="btn btn-outline" @onclick="OnBack">← Back</button>
        <button type="button" class="btn btn-primary" @onclick="OnNext">Next →</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetterText { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterTextChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;

    private async Task SetCoverLetterText(string value)
    {
        CoverLetterText = value;
        await CoverLetterTextChanged.InvokeAsync(value);
    }
}

@using sv_b3aee266d46a422aa507df110c2c832b.Models
@namespace sv_b3aee266d46a422aa507df110c2c832b.Components.Pages.Application

<div class="step-content">
    <h2>Review &amp; Submit</h2>

    @if (IsSubmitted)
    {
        <div class="confirmation">
            <div class="confirmation-icon">&#10003;</div>
            <h3>Application Submitted!</h3>
            <p>Your application has been received. Your confirmation number is:</p>
            <p class="application-id">#@ApplicationId</p>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="alert alert-error">@ErrorMessage</div>
        }

        <section class="review-section">
            <div class="review-header">
                <h3>Personal Information</h3>
                <button type="button" class="btn-link" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
            </div>
            <dl>
                <dt>Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </section>

        <section class="review-section">
            <div class="review-header">
                <h3>Work History</h3>
                <button type="button" class="btn-link" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-entry">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong>
                    <br />
                    <span class="text-muted">
                        @(entry.StartDate?.ToString("MMM yyyy") ?? "N/A") &ndash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-header">
                <h3>References</h3>
                <button type="button" class="btn-link" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="review-entry">
                    <strong>@r.Name</strong> — @r.Relationship
                    <br />
                    <span class="text-muted">@r.Email | @r.Phone</span>
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-header">
                <h3>Cover Letter</h3>
                <button type="button" class="btn-link" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </section>

        <div class="step-buttons">
            <button type="button" class="btn btn-outline" @onclick="OnBack">← Back</button>
            <button type="button" class="btn btn-primary btn-submit" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @(IsSubmitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    public bool IsSubmitting { get; set; }
    public bool IsSubmitted { get; set; }
    public int ApplicationId { get; set; }
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        ErrorMessage = null;
        StateHasChanged();

        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
            IsSubmitting = false;
        }
    }

    public void SetSubmitted(int applicationId)
    {
        ApplicationId = applicationId;
        IsSubmitted = true;
        IsSubmitting = false;
        StateHasChanged();
    }
}

