@page "/apply"
@rendermode InteractiveServer
@using sv_b3aee266d46a422aa507df110c2c832b.Components.Pages.Application
@using sv_b3aee266d46a422aa507df110c2c832b.Models
@using sv_b3aee266d46a422aa507df110c2c832b.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-page">
    <h1>Job Application</h1>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   StepNames="stepNames"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo"
                              OnNext="NextStep"
                              ValidateEmail="ApplicationService.ValidateEmailAsync" />
            break;

        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep References="references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;

        case 3:
            <CoverLetterStep @bind-CoverLetterText="coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 4:
            <ReviewStep @ref="reviewStepRef"
                        Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        OnBack="PreviousStep"
                        OnEditStep="GoToStep"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep = 0;
    private readonly HashSet<int> completedSteps = new();
    private ReviewStep? reviewStepRef;

    private readonly List<string> stepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    // Form state
    private readonly PersonalInfoModel personalInfo = new();
    private readonly List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private readonly List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        if (currentStep < stepNames.Count - 1)
            currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 0)
            currentStep--;
    }

    private void GoToStep(int step)
    {
        if (step >= 0 && step < stepNames.Count)
            currentStep = step;
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        var id = await ApplicationService.SubmitApplicationAsync(application);
        reviewStepRef?.SetSubmitted(id);
    }
}

.apply-page {
    max-width: 780px;
    margin: 0 auto;
    padding: 2rem 1rem;
}

.apply-page h1 {
    text-align: center;
    margin-bottom: 1.5rem;
    font-size: 1.75rem;
}

/* Step Indicator */
.step-list {
    display: flex;
    align-items: center;
    list-style: none;
    padding: 0;
    margin: 0 0 2rem;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    cursor: default;
    flex: 0 0 auto;
}

.step-item.completed {
    cursor: pointer;
}

.step-number {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #d1d5db;
    color: #9ca3af;
    background: #fff;
    transition: all 0.2s;
}

.step-item.current .step-number {
    background: #2563eb;
    border-color: #2563eb;
    color: #fff;
}

.step-item.completed .step-number {
    background: #16a34a;
    border-color: #16a34a;
    color: #fff;
}

.step-label {
    margin-top: 0.35rem;
    font-size: 0.75rem;
    color: #9ca3af;
    text-align: center;
    white-space: nowrap;
}

.step-item.current .step-label {
    color: #2563eb;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #16a34a;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #d1d5db;
    margin: 0 0.25rem;
    margin-bottom: 1.4rem;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #16a34a;
}

/* Step Content */
.step-content {
    background: #fff;
    border: 1px solid #e5e7eb;
    border-radius: 8px;
    padding: 1.5rem;
}

.step-content h2 {
    margin: 0 0 1.25rem;
    font-size: 1.3rem;
    color: #111827;
}

/* Forms */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.3rem;
    font-weight: 500;
    font-size: 0.9rem;
    color: #374151;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="tel"],
.form-group input[type="date"],
.form-group textarea {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #d1d5db;
    border-radius: 6px;
    font-size: 0.9rem;
    transition: border-color 0.15s;
    box-sizing: border-box;
}

.form-group input:focus,
.form-group textarea:focus {
    outline: none;
    border-color: #2563eb;
    box-shadow: 0 0 0 3px rgba(37, 99, 235, 0.1);
}

.form-row {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
}

.form-row .form-group {
    flex: 1;
    min-width: 180px;
}

.required {
    color: #dc2626;
}

.validation-hint {
    font-size: 0.8rem;
    color: #6b7280;
    font-style: italic;
}

/* Alerts */
.alert {
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-bottom: 1rem;
    font-size: 0.9rem;
}

