    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #d1d5db;
    color: #9ca3af;
    background: #fff;
    transition: all 0.2s;
}

.step-item.current .step-number {
    background: #2563eb;
    border-color: #2563eb;
    color: #fff;
}

.step-item.completed .step-number {
    background: #16a34a;
    border-color: #16a34a;
    color: #fff;
}

