    margin-top: 0.35rem;
    font-size: 0.75rem;
    color: #9ca3af;
    text-align: center;
    white-space: nowrap;
}

.step-item.current .step-label {
    color: #2563eb;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #16a34a;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #d1d5db;
    margin: 0 0.25rem;
    margin-bottom: 1.4rem;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #16a34a;
}

