.step-content {
    background: #fff;
    border: 1px solid #e5e7eb;
    border-radius: 8px;
    padding: 1.5rem;
}

.step-content h2 {
    margin: 0 0 1.25rem;
    font-size: 1.3rem;
    color: #111827;
}

