+    border: 1px solid #d1d5db;
+    border-radius: 6px;
+    font-size: 0.9rem;
+    transition: border-color 0.15s;
+    box-sizing: border-box;
+}
+
+.form-group input:focus,
+.form-group textarea:focus {
+    outline: none;
+    border-color: #2563eb;
+    box-shadow: 0 0 0 3px rgba(37, 99, 235, 0.1);
+}
+
+.form-row {
+    display: flex;
+    gap: 1rem;
+    flex-wrap: wrap;
+}
+
+.form-row .form-group {
+    flex: 1;
+    min-width: 180px;
+}
+
+.required {
+    color: #dc2626;
+}
+
+.validation-hint {
+    font-size: 0.8rem;
+    color: #6b7280;
+    font-style: italic;
+}
+
+/* Alerts */
+.alert {
+    padding: 0.75rem 1rem;
+    border-radius: 6px;
+    margin-bottom: 1rem;
+    font-size: 0.9rem;
+}
+
+.alert-error {
+    background: #fef2f2;
+    border: 1px solid #fecaca;
+    color: #dc2626;
+}
+
+/* Buttons */
+.btn {
+    padding: 0.5rem 1.25rem;
+    border: none;
+    border-radius: 6px;
+    font-size: 0.9rem;
+    font-weight: 500;
+    cursor: pointer;
+    transition: background 0.15s, opacity 0.15s;
+}
+
+.btn:disabled {
+    opacity: 0.6;
+    cursor: not-allowed;
+}
+
+.btn-primary {
+    background: #2563eb;
+    color: #fff;
+}
+
+.btn-primary:hover:not(:disabled) {
+    background: #1d4ed8;
+}
+
+.btn-outline {
+    background: transparent;
+    border: 1px solid #d1d5db;
+    color: #374151;
+}
+
+.btn-outline:hover {
+    background: #f9fafb;
+}
+
+.btn-secondary {
+    background: #f3f4f6;
+    color: #374151;
+    border: 1px solid #d1d5db;
+}
+
+.btn-secondary:hover {
+    background: #e5e7eb;
+}
+
+.btn-remove {
+    background: transparent;
+    color: #dc2626;
+    font-size: 0.8rem;
+    padding: 0.25rem 0.5rem;
+    float: right;
+}
+
+.btn-remove:hover {
+    background: #fef2f2;
+}
+
+.btn-link {
+    background: none;
+    border: none;
+    color: #2563eb;
+    cursor: pointer;
+    font-size: 0.85rem;
+    text-decoration: underline;
+    padding: 0;
+}
+
+.btn-link:hover {
+    color: #1d4ed8;
+}
+
+.btn-submit {
+    padding: 0.65rem 2rem;
+    font-size: 1rem;
+}
+
+/* Step Buttons */
+.step-buttons {
+    display: flex;
+    justify-content: space-between;
+    margin-top: 1.5rem;
+    padding-top: 1rem;
+    border-top: 1px solid #e5e7eb;
+}
+
+/* Fieldsets */
+fieldset {
+    border: 1px solid #e5e7eb;
+    border-radius: 6px;
+    padding: 1rem;
+    margin-bottom: 1rem;
+}
+
+fieldset legend {
+    font-weight: 600;
+    font-size: 0.9rem;
+    color: #374151;
+    padding: 0 0.5rem;
+}
+
+/* Character Count */
+.char-count {
+    text-align: right;
+    font-size: 0.8rem;
+    color: #6b7280;
+    margin-top: 0.3rem;
+}
+
+.char-count.over-limit {
+    color: #dc2626;
+}
+
+/* Review Step */
+.review-section {
+    border: 1px solid #e5e7eb;
+    border-radius: 6px;
+    padding: 1rem;
+    margin-bottom: 1rem;
+}
+
+.review-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    margin-bottom: 0.75rem;
+}
+
+.review-header h3 {
+    margin: 0;
+    font-size: 1rem;
+}
+
+.review-section dl {
+    display: grid;
+    grid-template-columns: 100px 1fr;
+    gap: 0.3rem 1rem;
+    margin: 0;
+    font-size: 0.9rem;
+}
+
+.review-section dt {
+    font-weight: 500;
+    color: #6b7280;
+}
+
+.review-section dd {
+    margin: 0;
+    color: #111827;
+}
+
+.review-entry {
+    padding: 0.5rem 0;
+    border-bottom: 1px solid #f3f4f6;
+    font-size: 0.9rem;
+}
+
+.review-entry:last-child {
+    border-bottom: none;
+}
+
+.text-muted {
+    color: #6b7280;
+    font-size: 0.85rem;
+}
+
+.cover-letter-preview {
+    white-space: pre-wrap;
+    background: #f9fafb;
+    padding: 0.75rem;
+    border-radius: 6px;
+    font-size: 0.9rem;
+    max-height: 200px;
+    overflow-y: auto;
+}
+
+/* Confirmation */
+.confirmation {
+    text-align: center;
+    padding: 2rem 1rem;
+}
+
+.confirmation-icon {
+    width: 64px;
+    height: 64px;
+    background: #16a34a;
+    color: #fff;
+    border-radius: 50%;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    font-size: 2rem;
+    margin: 0 auto 1rem;
+}
+
+.confirmation h3 {
+    color: #16a34a;
+    font-size: 1.5rem;
+    margin-bottom: 0.5rem;
+}
+
+.application-id {
+    font-size: 1.75rem;
+    font-weight: 700;
+    color: #2563eb;
+}
+
+/* Checkbox styling */
+.form-group input[type="checkbox"] {
+    margin-right: 0.4rem;
+    vertical-align: middle;
+}
+

toolArgs.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_b3aee266d46a422aa507df110c2c832b.Components.Pages.Application
@using sv_b3aee266d46a422aa507df110c2c832b.Models
@using sv_b3aee266d46a422aa507df110c2c832b.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-page">
    <h1>Job Application</h1>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   StepNames="stepNames"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo"
                              OnNext="NextStep"
                              ValidateEmail="ApplicationService.ValidateEmailAsync" />
            break;

        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep References="references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;

        case 3:
            <CoverLetterStep @bind-CoverLetterText="coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 4:
            <ReviewStep @ref="reviewStepRef"
                        Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        OnBack="PreviousStep"
                        OnEditStep="GoToStep"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep = 0;
    private readonly HashSet<int> completedSteps = new();
    private ReviewStep? reviewStepRef;

    private readonly List<string> stepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    // Form state
    private readonly PersonalInfoModel personalInfo = new();
    private readonly List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private readonly List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        if (currentStep < stepNames.Count - 1)
            currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 0)
            currentStep--;
    }

    private void GoToStep(int step)
    {
        if (step >= 0 && step < stepNames.Count)
            currentStep = step;
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        var id = await ApplicationService.SubmitApplicationAsync(application);
        reviewStepRef?.SetSubmitted(id);
    }
}

